const { getAuthClient } = require\('./lib/auth'\);
const { google } = require\('googleapis'\);

\(async \(\) => {
  const auth = await getAuthClient\(\);
  const sc = google.searchconsole\({ version: 'v1', auth }\);
  const siteUrl = 'https://www.coreltb.pl/';

  // ALL QUERIES 12 months
  const queries = await sc.searchanalytics.query\({
    siteUrl,
    requestBody: {
      startDate: '2025-03-01',
      endDate: '2026-03-09',
      dimensions: ['query'],
      rowLimit: 1000,
      dataState: 'all',
    },
  }\);
  const rows = queries.data.rows || [];
  console.log\('TOTAL_QUERIES:' + rows.length\);
  for \(const r of rows.sort\(\(a,b\) => b.impressions - a.impressions\)\) {
    console.log\('Q|' + [r.keys[0], r.clicks, r.impressions, \(r.ctr*100\).toFixed\(1\), r.position.toFixed\(1\)].join\('|'\)\);
  }
}\)\(\).catch\(e => console.error\('ERR:' + e.message\)\);
" 2>&1 | head -200)

Bash(powershell.exe -Command "
Get-ChildItem -Path 'D:\\' -Filter '*.bat' -Recurse -Depth 3 -ErrorAction SilentlyContinue | ForEach-Object {
    \\$content = Get-Content \\$_.FullName -Raw -ErrorAction SilentlyContinue
    if \(\\$content -and \\$content.Contains\('LOCALAPPDATA%MicrosoftWindowsApps'\)\) {
        \\$fixed = \\$content.Replace\('%LOCALAPPDATA%MicrosoftWindowsAppswt.exe', '%LOCALAPPDATA%\\Microsoft\\WindowsApps\\wt.exe'\)
        Set-Content -Path \\$_.FullName -Value \\$fixed -NoNewline
        Write-Host \('FIXED: ' + \\$_.FullName\)
    }
}
Write-Host 'Done!'
")

